import React from 'react';
import { Link } from 'react-router-dom'; // We'll use this for Step 3

function SplashPage() {
  return (
    <div className="splash-container">
      <div className="splash-content">
        <h1>Welcome to My Blog</h1>
        <p>Explore stories, tutorials, and insights.</p>
        {/* We use Link instead of <a href> to prevent page reloads [cite: 170, 189] */}
        <Link to="/home" className="enter-button">Enter Blog</Link>
      </div>
    </div>
  );
}

export default SplashPage;
